   153вЖТ	if err := ValidateDevmachineForModify(request.Name, request.Namespace, request.ImageName); err != nil {
   154вЖТ		return nil, NewValidationError("devmachine", request.Name, err)
   155вЖТ	}
   156вЖТ
   157вЖТ	// 1. иОЈеПЦзО∞жЬЙ Deployment
   158вЖТ	deployment, err := s.k8sClient.GetDeployment(ctx, request.Namespace, request.Name)
   159вЖТ	if err != nil {
   160вЖТ		return nil, NewResourceError("Deployment", request.Name, "get", err)
   161вЖТ	}
   162вЖТ
   163вЖТ	// 2. жЫіжЦ∞ Deployment йЕНзљЃ
   164вЖТ	deployment.Spec.Template.Spec.Containers[0].Image = request.ImageName
   165вЖТ
   166вЖТ	// жЫіжЦ∞иµДжЇРиѓЈж±В
   167вЖТ	if request.CPU != "" || request.Memory != "" || request.GPU != "" {
   168вЖТ		// жЮДеїЇжЦ∞зЪДиµДжЇРиѓЈж±В
   169вЖТ		resources := BuildResourceRequirements(request.CPU, request.Memory, request.GPU, request.GPUName)
   170вЖТ		deployment.Spec.Template.Spec.Containers[0].Resources = resources
   171вЖТ	}
   172вЖТ
   173вЖТ	// жЫіжЦ∞иКВзВєйАЙжЛ©еЩ®
   174вЖТ	if len(request.NodeSelector) > 0 {
   175вЖТ		deployment.Spec.Template.Spec.NodeSelector = request.NodeSelector
   176вЖТ	}
   177вЖТ
   178вЖТ	// жЫіжЦ∞ж†Зз≠Њ
   179вЖТ	if len(request.Labels) > 0 {
   180вЖТ		for k, v := range request.Labels {
   181вЖТ			deployment.Labels[k] = v
   182вЖТ			deployment.Spec.Template.Labels[k] = v
   183вЖТ		}
   184вЖТ	}
   185вЖТ
   186вЖТ	// жЫіжЦ∞ж≥®иІ£
   187вЖТ	if len(request.Annotations) > 0 {
   188вЖТ		for k, v := range request.Annotations {
   189вЖТ			deployment.Annotations[k] = v
   190вЖТ			deployment.Spec.Template.Annotations[k] = v
   191вЖТ		}
   192вЖТ	}
   193вЖТ
   194вЖТ	// жЫіжЦ∞йШЯеИЧеРНзІ∞
   195вЖТ	if request.QueueName != "" {
   196вЖТ		deployment.Spec.Template.Annotations[volcanoQueueName] = request.QueueName
   197вЖТ	}
   198вЖТ
   199вЖТ	// 3. жЫіжЦ∞ Deployment
   200вЖТ	if err := s.k8sClient.UpdateDeployment(ctx, deployment); err != nil {
   201вЖТ		return nil, NewResourceError("Deployment", request.Name, "update", err)
   202вЖТ	}
   203вЖТ
   204вЖТ	// ињФеЫЮжЫіжЦ∞жЧґйЧі
   205вЖТ	return &devmachinemodel.UpdateDevmachineResponse{
   206вЖТ		UpdateAt: time.Now().Format(time.RFC3339),
   207вЖТ	}, nil
   208вЖТ}
