   210вЖТfunc (s *service) DeleteDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.DeleteDevmachineResponse, error) {
   211вЖТ	// 1. еИ†йЩ§ Ingress
   212вЖТ	if err := s.k8sClient.DeleteIngress(ctx, namespace, name+ingressSuffix); err != nil {
   213вЖТ		// иЃ∞ељХйФЩиѓѓдљЖзїІзї≠еИ†йЩ§еЕґдїЦиµДжЇР
   214вЖТ		log.Printf("warning: failed to delete ingress: %v\n", err)
   215вЖТ	}
   216вЖТ
   217вЖТ	// 2. еИ†йЩ§ Service
   218вЖТ	if err := s.k8sClient.DeleteService(ctx, namespace, name+serviceSuffix); err != nil {
   219вЖТ		log.Printf("warning: failed to delete service: %v\n", err)
   220вЖТ	}
   221вЖТ
   222вЖТ	// 3. еИ†йЩ§ Deployment
   223вЖТ	if err := s.k8sClient.DeleteDeployment(ctx, namespace, name); err != nil {
   224вЖТ		log.Printf("warning: failed to delete deployment: %v\n", err)
   225вЖТ	}
   226вЖТ
   227вЖТ	// 4. еИ†йЩ§ PVC еТМ PV
   228вЖТ	// еИЧеЗЇиѓ•еЉАеПСжЬЇзЪДжЙАжЬЙ PVC
   229вЖТ	pvcs, err := s.k8sClient.ListPVCs(ctx, namespace)
   230вЖТ	if err != nil {
   231вЖТ		log.Printf("warning: failed to list PVCs: %v\n", err)
   232вЖТ	}
   233вЖТ
   234вЖТ	// еИ†йЩ§е±ЮдЇОиѓ•еЉАеПСжЬЇзЪД PVC еТМеѓєеЇФзЪД PV
   235вЖТ	for _, pvc := range pvcs {
   236вЖТ		// ж£АжЯ• PVC еРНзІ∞жШѓеР¶еМєйЕНиѓ•еЉАеПСжЬЇ
   237вЖТ		if IsPVCBelongsToDevmachine(pvc.Name, namespace, name) {
   238вЖТ			pvName := pvc.Spec.VolumeName
   239вЖТ
   240вЖТ			// еИ†йЩ§ PVC
   241вЖТ			if err := s.k8sClient.DeletePVC(ctx, namespace, pvc.Name); err != nil {
   242вЖТ				log.Printf("warning: failed to delete PVC %s: %v\n", pvc.Name, err)
   243вЖТ			}
   244вЖТ
   245вЖТ			// еИ†йЩ§еѓєеЇФзЪД PV
   246вЖТ			if pvName != "" {
   247вЖТ				if err := s.k8sClient.DeletePV(ctx, pvName); err != nil {
   248вЖТ					log.Printf("warning: failed to delete PV %s: %v\n", pvName, err)
   249вЖТ				}
   250вЖТ			}
   251вЖТ		}
   252вЖТ	}
   253вЖТ
   254вЖТ	// ињФеЫЮеИ†йЩ§жЧґйЧі
   255вЖТ	return &devmachinemodel.DeleteDevmachineResponse{
   256вЖТ		DeleteAt: time.Now().Format(time.RFC3339),
   257вЖТ	}, nil
   258вЖТ}
