   260вЖТfunc (s *service) GetDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.GetDevmachineResponse, error) {
   261вЖТ	// й™МиѓБиѓЈж±ВеПВжХ∞
   262вЖТ	if err := ValidateDevmachineRequest(name, namespace, ""); err != nil && namespace != "" && name != "" {
   263вЖТ		return nil, NewValidationError("devmachine", name, err)
   264вЖТ	}
   265вЖТ
   266вЖТ	// иОЈеПЦ Deployment дњ°жБѓ
   267вЖТ	deployment, err := s.k8sClient.GetDeployment(ctx, namespace, name)
   268вЖТ	if err != nil {
   269вЖТ		return nil, NewResourceError("Deployment", name, "get", err)
   270вЖТ	}
   271вЖТ
   272вЖТ	// иОЈеПЦ Service дњ°жБѓ
   273вЖТ	service, err := s.k8sClient.GetService(ctx, namespace, name+serviceSuffix)
   274вЖТ	if err != nil {
   275вЖТ		return nil, NewResourceError("Service", name+serviceSuffix, "get", err)
   276вЖТ	}
   277вЖТ
   278вЖТ	// иОЈеПЦ Ingress дњ°жБѓ
   279вЖТ	ingress, err := s.k8sClient.GetIngress(ctx, namespace, name+ingressSuffix)
   280вЖТ	if err != nil {
   281вЖТ		return nil, NewResourceError("Ingress", name+ingressSuffix, "get", err)
   282вЖТ	}
   283вЖТ
   284вЖТ	if deployment == nil || service == nil || ingress == nil {
   285вЖТ		return nil, fmt.Errorf("deployment or service or ingress not found")
   286вЖТ	}
   287вЖТ
   288вЖТ	// иОЈеПЦдЄОDeploymentеЕ≥иБФзЪДе≠ШеВ®дњ°жБѓ
   289вЖТ	var storage []devmachinemodel.Storage
   290вЖТ
   291вЖТ	// дїОDeploymentзЪДPodж®°жЭњдЄ≠иОЈеПЦеНЈдњ°жБѓ
   292вЖТ	volumes := deployment.Spec.Template.Spec.Volumes
   293вЖТ	for _, volume := range volumes {
   294вЖТ		// ж£АжЯ•еНЈжШѓеР¶жШѓPVCз±їеЮЛзЪД
   295вЖТ		if volume.PersistentVolumeClaim != nil {
   296вЖТ			pvcName := volume.PersistentVolumeClaim.ClaimName
   297вЖТ
   298вЖТ			// иОЈеПЦеЕЈдљУзЪДPVCдњ°жБѓ
   299вЖТ			pvc, err := s.k8sClient.GetPVC(ctx, namespace, pvcName)
   300вЖТ			if err != nil || pvc == nil {
   301вЖТ				continue
   302вЖТ			}
   303вЖТ
   304вЖТ			// ж£АжЯ•PVCжШѓеР¶е±ЮдЇОељУеЙНеЉАеПСжЬЇ
   305вЖТ			if IsPVCBelongsToDevmachine(pvc.Name, namespace, name) {
   306вЖТ				// дїОPVCиОЈеПЦжМВиљљиЈѓеЊД
   307вЖТ				mountPath := GetMountPathForPVCByName(pvcName)
   308вЖТ
   309вЖТ				// дїОPVдЄ≠иОЈеПЦе≠ШеВ®иЈѓеЊД
   310вЖТ				if pvc.Spec.VolumeName != "" {
   311вЖТ					pv, err := s.k8sClient.GetPV(ctx, pvc.Spec.VolumeName)
   312вЖТ					if err == nil && pv != nil {
   313вЖТ						// дїО PV зЪД VolumeAttributes дЄ≠иОЈеПЦ subPath
   314вЖТ						if juicefsSubPath, exists := pv.Spec.CSI.VolumeAttributes["subPath"]; exists {
   315вЖТ							storage = append(storage, devmachinemodel.Storage{
   316вЖТ								MountPath:   mountPath,
   317вЖТ								StoragePath: juicefsSubPath,
   318вЖТ							})
   319вЖТ						}
   320вЖТ					}
   321вЖТ				}
   322вЖТ			}
   323вЖТ		}
   324вЖТ	}
   325вЖТ
   326вЖТ	// жПРеПЦ GPU дњ°жБѓ
   327вЖТ	gpu := "0"
   328вЖТ	gpuName := ""
   329вЖТ	if len(deployment.Spec.Template.Spec.Containers) > 0 {
   330вЖТ		container := deployment.Spec.Template.Spec.Containers[0]
   331вЖТ		if gpuResource, exists := container.Resources.Requests["hygon.com/dcu"]; exists {
   332вЖТ			gpu = gpuResource.String()
   333вЖТ			gpuName = "hygon.com/dcu"
   334вЖТ		} else if gpuResource, exists := container.Resources.Requests["nvidia.com/gpu"]; exists {
   335вЖТ			gpu = gpuResource.String()
   336вЖТ			gpuName = "nvidia.com/gpu"
   337вЖТ		}
   338вЖТ	}
   339вЖТ
   340вЖТ	// иОЈеПЦ WebIDE з±їеЮЛ
   341вЖТ	webIDE := GetWebIDEType(deployment)
   342вЖТ
   343вЖТ	// жЮДеїЇеУНеЇФ
   344вЖТ	response := &devmachinemodel.GetDevmachineResponse{
   345вЖТ		Devmachine: devmachinemodel.Devmachine{
   346вЖТ			Namespace:   deployment.Namespace,
   347вЖТ			Name:        deployment.Name,
   348вЖТ			QueueName:   deployment.Spec.Template.Annotations[volcanoQueueName],
   349вЖТ			ImageName:   deployment.Spec.Template.Spec.Containers[0].Image,
   350вЖТ			CPU:         deployment.Spec.Template.Spec.Containers[0].Resources.Requests.Cpu().String(),
   351вЖТ			Memory:      deployment.Spec.Template.Spec.Containers[0].Resources.Requests.Memory().String(),
   352вЖТ			GPU:         gpu,
   353вЖТ			GPUName:     gpuName,
   354вЖТ			WebIDE:      webIDE,
   355вЖТ			WebUrl:      fmt.Sprintf("http://%s", GlobalIngressURL+BuildIngressPath(namespace, name)),
   356вЖТ			Storage:     storage,
   357вЖТ			Annotations: deployment.Annotations,
   358вЖТ			Labels:      deployment.Labels,
   359вЖТ			Status:      getStatusFromDeployment(deployment),
   360вЖТ		},
   361вЖТ	}
   362вЖТ
   363вЖТ	return response, nil
   364вЖТ}
   365вЖТ
   366вЖТ// getStatusFromDeployment дїОDeploymentиОЈеПЦзКґжАБ
   367вЖТ// TODO: жЈїеК†podзЇІеИЂзЪДзКґжАБеИ§жЦ≠
   368вЖТfunc getStatusFromDeployment(deployment *appsv1.Deployment) string {
   369вЖТ	if deployment.Status.ReadyReplicas > 0 {
   370вЖТ		return "running"
   371вЖТ	}
   372вЖТ	if deployment.Status.Replicas == 0 {
   373вЖТ		return "stopped"
   374вЖТ	}
   375вЖТ	return "pending"
   376вЖТ}
