   378вЖТfunc (s *service) ListDevmachines(ctx context.Context, devmachines []devmachinemodel.DevmachineName) ([]devmachinemodel.Devmachine, error) {
   379вЖТ	// е¶ВжЮЬж≤°жЬЙжМЗеЃЪдїїдљХdevmachineпЉМеИЩињФеЫЮз©ЇеИЧи°®
   380вЖТ	if len(devmachines) == 0 {
   381вЖТ		return []devmachinemodel.Devmachine{}, nil
   382вЖТ	}
   383вЖТ
   384вЖТ	// еИЭеІЛеМЦзїУжЮЬеИЗзЙЗ
   385вЖТ	results := make([]devmachinemodel.Devmachine, len(devmachines))
   386вЖТ	errors := make([]error, len(devmachines))
   387вЖТ
   388вЖТ	// еЃЪдєЙеЈ•дљЬеЗљжХ∞
   389вЖТ	workerFunc := func(piece int) {
   390вЖТ		// иОЈеПЦжМЗеЃЪзЪДdevmachine
   391вЖТ		devmachine := devmachines[piece]
   392вЖТ		// и∞ГзФ®GetDevmachineиОЈеПЦиѓ¶зїЖдњ°жБѓ
   393вЖТ		result, err := s.GetDevmachine(ctx, devmachine.Namespace, devmachine.Name)
   394вЖТ		if err != nil {
   395вЖТ			errors[piece] = err
   396вЖТ		} else {
   397вЖТ			results[piece] = result.Devmachine
   398вЖТ		}
   399вЖТ	}
   400вЖТ
   401вЖТ	// дљњзФ®workqueue.ParallelizeUntilињЫи°Меєґи°Ме§ДзРЖ
   402вЖТ	// йЩРеИґжЬАе§ІеєґеПСжХ∞дї•йБњеЕНеѓєk8s APIжЬНеК°еЩ®йА†жИРињЗе§ІеОЛеКЫ
   403вЖТ	maxWorkers := 10
   404вЖТ	workqueue.ParallelizeUntil(ctx, maxWorkers, len(devmachines), workerFunc)
   405вЖТ
   406вЖТ	// жФґйЫЖжИРеКЯзЪДзїУжЮЬ
   407вЖТ	var successfulResults []devmachinemodel.Devmachine
   408вЖТ	for i, err := range errors {
   409вЖТ		if err == nil {
   410вЖТ			successfulResults = append(successfulResults, results[i])
   411вЖТ		} else {
   412вЖТ			log.Printf("warning: failed to get devmachine %s/%s: %v", devmachines[i].Namespace, devmachines[i].Name, err)
   413вЖТ		}
   414вЖТ	}
   415вЖТ
   416вЖТ	return successfulResults, nil
   417вЖТ}
