    59вЖТ// StartCSISyncLoop еРѓеК®CSIйЕНзљЃеРМж≠•еЊ™зОѓ
    60вЖТfunc StartCSISyncLoop(k8sClient k8s.Client) {
    61вЖТ	// дљњзФ®wait.UntilеРѓеК®еЃЪжЧґеРМж≠•еЊ™зОѓ
    62вЖТ	go wait.Until(func() {
