    74вЖТ// getStorageClassInfo дїОk8sиОЈеПЦStorageClassдњ°жБѓеєґиљђжНҐдЄЇCSIConfig
    75вЖТfunc getStorageClassInfo(k8sClient k8s.Client, className string) (*CSIConfig, error) {
    76вЖТ	ctx := context.Background()
    77вЖТ	if k8sClient == nil {
    78вЖТ		return nil, fmt.Errorf("k8s client is nil")
    79вЖТ	}
    80вЖТ	sc, err := k8sClient.GetStorageClass(ctx, className)
    81вЖТ	if err != nil {
    82вЖТ		return nil, fmt.Errorf("failed to get storage class %s: %w", className, err)
    83вЖТ	}
    84вЖТ
    85вЖТ	config := &CSIConfig{
    86вЖТ		Driver:            sc.Provisioner,
    87вЖТ		ReclaimPolicy:     *sc.ReclaimPolicy,
    88вЖТ		VolumeBindingMode: *sc.VolumeBindingMode,
    89вЖТ		Parameters:        make(map[string]string),
    90вЖТ		MountOptions:      make([]string, len(sc.MountOptions)),
    91вЖТ	}
    92вЖТ
    93вЖТ	// е§НеИґеПВжХ∞
    94вЖТ	for k, v := range sc.Parameters {
    95вЖТ		config.Parameters[k] = v
    96вЖТ	}
    97вЖТ
    98вЖТ	// е§НеИґжМВиљљйАЙй°є
    99вЖТ	copy(config.MountOptions, sc.MountOptions)
   100вЖТ
   101вЖТ	// дїОеПВжХ∞дЄ≠жПРеПЦ Secret дњ°жБѓ
   102вЖТ	if secretName, exists := config.Parameters["csi.storage.k8s.io/node-publish-secret-name"]; exists {
   103вЖТ		config.SecretName = secretName
   104вЖТ	}
   105вЖТ	if secretNamespace, exists := config.Parameters["csi.storage.k8s.io/node-publish-secret-namespace"]; exists {
   106вЖТ		config.SecretNamespace = secretNamespace
   107вЖТ	}
   108вЖТ	if juiceFSImage, exists := config.Parameters["juicefs/mount-image"]; exists {
   109вЖТ		config.JuiceFSImage = juiceFSImage
   110вЖТ	}
   111вЖТ
   112вЖТ	return config, nil
   113вЖТ}
