   124вЖТ// buildSharedPV жЮДеїЇеЕ±дЇЂ PersistentVolume
   125вЖТ// дљњзФ®йЫЖзЊ§зЇІеИЂеЕ±дЇЂ PVпЉМReclaimPolicy дЄЇ RetainпЉИеМЇеИЂдЇОжЧІзЪД DeleteпЉЙ
   126вЖТfunc buildSharedPV(name, subPath string, readOnly bool) *corev1.PersistentVolume {
   127вЖТ	configMutex.RLock()
   128вЖТ	defer configMutex.RUnlock()
   129вЖТ
   130вЖТ	accessMode := corev1.ReadWriteMany
   131вЖТ	if readOnly {
   132вЖТ		accessMode = corev1.ReadOnlyMany
   133вЖТ	}
   134вЖТ
   135вЖТ	volumeMode := corev1.PersistentVolumeFilesystem
   136вЖТ	pv := &corev1.PersistentVolume{
   137вЖТ		ObjectMeta: metav1.ObjectMeta{
   138вЖТ			Name: name,
   139вЖТ		},
   140вЖТ		Spec: corev1.PersistentVolumeSpec{
   141вЖТ			Capacity: corev1.ResourceList{
   142вЖТ				corev1.ResourceStorage: resource.MustParse(defaultStorageSize),
   143вЖТ			},
   144вЖТ			VolumeMode:  &volumeMode,
   145вЖТ			AccessModes: []corev1.PersistentVolumeAccessMode{accessMode},
   146вЖТ			PersistentVolumeReclaimPolicy: corev1.PersistentVolumeReclaimRetain,
   147вЖТ			PersistentVolumeSource: corev1.PersistentVolumeSource{
   148вЖТ				CSI: &corev1.CSIPersistentVolumeSource{
   149вЖТ					Driver: csiConfig.Driver,
   150вЖТ					FSType: "juicefs",
   151вЖТ					NodePublishSecretRef: &corev1.SecretReference{
   152вЖТ						Name:      csiConfig.SecretName,
   153вЖТ						Namespace: csiConfig.SecretNamespace,
   154вЖТ					},
   155вЖТ					VolumeHandle:     name,
   156вЖТ					VolumeAttributes: map[string]string{},
   157вЖТ				},
   158вЖТ			},
   159вЖТ		},
   160вЖТ	}
   161вЖТ
   162вЖТ	if csiConfig.MountOptions != nil {
   163вЖТ		pv.Spec.MountOptions = csiConfig.MountOptions
   164вЖТ	}
   165вЖТ	for k, v := range csiConfig.Parameters {
   166вЖТ		pv.Spec.CSI.VolumeAttributes[k] = v
   167вЖТ	}
   168вЖТ	if subPath != "" {
   169вЖТ		pv.Spec.CSI.VolumeAttributes["subPath"] = subPath
   170вЖТ	}
   171вЖТ
   172вЖТ	return pv
   173вЖТ}
