   175вЖТ// buildSharedPVC жЮДеїЇ namespace зЇІеЕ±дЇЂ PersistentVolumeClaim
   176вЖТ// йАЪињЗ spec.volumeName жШЊеЉПзїСеЃЪеИ∞йЫЖзЊ§еЕ±дЇЂ PV
   177вЖТfunc buildSharedPVC(namespace, pvcName, pvName string, readOnly bool) *corev1.PersistentVolumeClaim {
   178вЖТ	accessMode := corev1.ReadWriteMany
   179вЖТ	if readOnly {
   180вЖТ		accessMode = corev1.ReadOnlyMany
   181вЖТ	}
   182вЖТ
   183вЖТ	storageClass := ""
   184вЖТ	return &corev1.PersistentVolumeClaim{
   185вЖТ		ObjectMeta: metav1.ObjectMeta{
   186вЖТ			Name:      pvcName,
   187вЖТ			Namespace: namespace,
   188вЖТ		},
   189вЖТ		Spec: corev1.PersistentVolumeClaimSpec{
   190вЖТ			VolumeName:       pvName,
   191вЖТ			AccessModes:      []corev1.PersistentVolumeAccessMode{accessMode},
   192вЖТ			StorageClassName: &storageClass,
   193вЖТ			Resources: corev1.VolumeResourceRequirements{
   194вЖТ				Requests: corev1.ResourceList{
