   202вЖТ// buildSharedVolumes ж†єжНЃ storage еИЧи°®жЮДеїЇеЕ±дЇЂеНЈпЉИеОїйЗНпЉМжЬАе§Ъ 2 дЄ™пЉЙ
   203вЖТ// ReadOnly=false зЪД storage еЕ±зФ® shared-rw-volume
   204вЖТ// ReadOnly=true  зЪД storage еЕ±зФ® shared-ro-volume
   205вЖТfunc buildSharedVolumes(storages []devmachinemodel.Storage) []corev1.Volume {
   206вЖТ	if len(storages) == 0 {
   207вЖТ		return nil
   208вЖТ	}
   209вЖТ
   210вЖТ	volumes := make([]corev1.Volume, 0, 2)
   211вЖТ	hasRW, hasRO := false, false
   212вЖТ
   213вЖТ	for _, s := range storages {
   214вЖТ		if !s.ReadOnly && !hasRW {
   215вЖТ			hasRW = true
   216вЖТ			volumes = append(volumes, corev1.Volume{
   217вЖТ				Name: SharedRWVolumeName,
   218вЖТ				VolumeSource: corev1.VolumeSource{
   219вЖТ					PersistentVolumeClaim: &corev1.PersistentVolumeClaimVolumeSource{
   220вЖТ						ClaimName: SharedRWPVCName,
   221вЖТ					},
   222вЖТ				},
   223вЖТ			})
   224вЖТ		}
   225вЖТ		if s.ReadOnly && !hasRO {
   226вЖТ			hasRO = true
   227вЖТ			volumes = append(volumes, corev1.Volume{
   228вЖТ				Name: SharedROVolumeName,
   229вЖТ				VolumeSource: corev1.VolumeSource{
   230вЖТ					PersistentVolumeClaim: &corev1.PersistentVolumeClaimVolumeSource{
   231вЖТ						ClaimName: SharedROPVCName,
   232вЖТ						ReadOnly:  true,
   233вЖТ					},
   234вЖТ				},
   235вЖТ			})
   236вЖТ		}
   237вЖТ	}
   238вЖТ
   239вЖТ	return volumes
   240вЖТ}
   241вЖТ
   242вЖТ// buildSharedVolumeMounts жЮДеїЇеЕ±дЇЂеНЈжМВиљљеИЧи°®пЉИжѓПжЭ° storage зЛђзЂЛжМВиљљпЉМsubPath йЪФз¶їпЉЙ
   243вЖТfunc buildSharedVolumeMounts(storages []devmachinemodel.Storage) []corev1.VolumeMount {
   244вЖТ	if len(storages) == 0 {
   245вЖТ		return nil
   246вЖТ	}
   247вЖТ
   248вЖТ	mounts := make([]corev1.VolumeMount, 0, len(storages))
   249вЖТ	for _, s := range storages {
   250вЖТ		volName := SharedRWVolumeName
   251вЖТ		if s.ReadOnly {
   252вЖТ			volName = SharedROVolumeName
   253вЖТ		}
   254вЖТ		mounts = append(mounts, corev1.VolumeMount{
   255вЖТ			Name:      volName,
   256вЖТ			MountPath: s.MountPath,
   257вЖТ			SubPath:   s.StoragePath,
   258вЖТ			ReadOnly:  s.ReadOnly,
   259вЖТ		})
   260вЖТ	}
   261вЖТ
   262вЖТ	return mounts
   263вЖТ}
